import{_ as e,o as a,c as d,ag as r}from"./chunks/framework.DXGyWiRo.js";const n="/images/lekt0801.jpg",i="/images/lekt0803.jpg",u="/images/lekt0807.jpg",s="/images/lekt0802.jpg",l="/images/lekt0804.jpg",o="/images/lekt0805.jpg",h="/images/lekt0808.jpg",p="/images/lekt0809.jpg",m="/images/lekt0810.jpg",w=JSON.parse('{"title":"Lektion 8","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion08.md","filePath":"lektionen/lektion08.md"}'),b={name:"lektionen/lektion08.md"};function g(c,t,k,f,q,z){return a(),d("div",null,[...t[0]||(t[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-8" tabindex="-1">Lektion 8 <a class="header-anchor" href="#lektion-8" aria-label="Permalink to &quot;Lektion 8&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>8.1. Zur Bildung von Nomina</li><li>8.2. Einteilung der Nominalsuffixe</li><li>8.3. Einige wichtige Nominalsuffixe <ul><li>8.3.1. -a m. (kṛt)</li><li>8.3.2. -ana n. (kṛt)</li><li>8.3.3. -tra n. (kṛt)</li><li>8.3.4. -ti f. (kṛt)</li><li>8.3.5. -tva n., tā f. (taddhita)</li></ul></li><li>8.4. Die 8. Präsensklasse (tanādi = तनादि = &quot;tan usw.&quot;)</li><li>8.5. Wortliste</li><li>8.6. Übung</li><li>8.7. Lese- und Übersetzungsübung</li></ul><h2 id="_8-1-zur-bildung-von-nomina" tabindex="-1">8.1. Zur Bildung von Nomina <a class="header-anchor" href="#_8-1-zur-bildung-von-nomina" aria-label="Permalink to &quot;8.1. Zur Bildung von Nomina&quot;">​</a></h2><p>In der traditionellen indischen Grammatik unterscheidet man bei den Suffixen, mit denen Nominalstämme gebildet werden:</p><ul><li>kṛt-Suffixe (कृत्) (Primärsuffixe): bilden aus Verbalwurzeln (dhātu m. = धातु) und Verbalstämmen Nominalstämme, Absolutiva und Infinitive</li><li>taddhita-Suffixe (तद्धित) (Sekundärsuffixe): treten an Nominalstämme und Indeklinabilia und bilden neue Nominalstämme bze. Indeklinabilia</li></ul><p>Schema:</p><p>Wurzel + kṛt-Suffix » Nominalstamm usw. + taddhita-Suffix » neuer Nominalstamm usw.</p><p>Nominalstamm + Kasusendung » syntaxfähiges Nomen</p><h2 id="_8-2-einteilung-der-nominalsuffixe" tabindex="-1">8.2. Einteilung der Nominalsuffixe <a class="header-anchor" href="#_8-2-einteilung-der-nominalsuffixe" aria-label="Permalink to &quot;8.2. Einteilung der Nominalsuffixe&quot;">​</a></h2><ul><li>kṛt (kṛdanta) = कृत् (कृदन्त) <ul><li>kārakakṛt कारककृत् » nomina agentis (bezeichnen jemanden, der das durch die Wurzel Bezeichnete tut)</li><li>kṛtikṛt कृतिकृत् » nomina actionis (bezeichnen die durch die Wurzel ausgedrückte Handlung) bzw. Abstrakta</li></ul></li><li>taddhita <ul><li>viśeṣyataddhita विशेष्यतद्धित » Adjektive</li><li>bhāvārthakataddhita (tanmātrataddhita) भावार्थकतद्धित (तन्मात्रतद्धित) » Abstrakta</li><li>tadvattaddhita (तद्वत्तद्धित) » bbesitzanzeigend (z.B. -mant -मन्त्, -vant -वन्त्)</li><li>tolanataddhita (atiśāyanataddhita) तोलनतद्धित (अतिशायनतद्धित) » Steigerung (Komparativ, Superlativ), Vergleich</li><li>pūraṇataddhita पूरणतद्धित » Ordinalzahlen (erster usw.)</li><li>vibhaktitaddhita विभक्तितद्धित » anstelle von Kasusendungen (z.B. -tas -तस्, -tra -त्र)</li><li>abhūtatadbhāva (cvitaddhita) अभूततद्भाव (च्वितद्धित) » (cvi-Bildungen च्वि, -sāt -सात्)</li></ul></li></ul><p>Einteilung nach dem Ablaut:</p><ul><li>guṇya गुण्य: hochstufige Bildung</li><li>na guṇya न गुण्य : tiefstufige Bildung</li><li>vṛddhyarha वृद्ध्यर्ह : dehnstufige Bildungस्</li></ul><h2 id="_8-3-einige-wichtige-nominalsuffixe" tabindex="-1">8.3. Einige wichtige Nominalsuffixe <a class="header-anchor" href="#_8-3-einige-wichtige-nominalsuffixe" aria-label="Permalink to &quot;8.3. Einige wichtige Nominalsuffixe&quot;">​</a></h2><h3 id="_8-3-1-a-m-krt" tabindex="-1">8.3.1. -a m. (kṛt) <a class="header-anchor" href="#_8-3-1-a-m-krt" aria-label="Permalink to &quot;8.3.1. -a m. (kṛt)&quot;">​</a></h3><p>Das kṛt-Suffix -a bildet maskuline (seltener neutrale) Substantive, die eine Handlung oder einen Zustand  bezeichnen, der durch die Wurzel bezeichnet wird; manchmal auch Adjektive oder Substantive, die den Agens (kartṛ) der von der Verbalwurzel bezeichneten handlung ausdrücken. Für kurze Penultima (= Vokal vor Konsonant, auf den die Wurzel auslautet) oder auslautenden Wurzelvokal wir meist Hochstufe (guṇa) oder Dehnstufe (vṛddhi) substituiert.</p><p>Beispiele:</p><table tabindex="0"><thead><tr><th>Wurzel</th><th>+ -a (kṛt)</th></tr></thead><tbody><tr><td>ji 1 P &quot;siegen&quot;</td><td></td></tr><tr><td>जि</td><td>jaya m. &quot;das Siegen, der Sieg&quot;</td></tr><tr><td>जय</td><td></td></tr><tr><td>muh 4 P &quot;verwirrt sein&quot;</td><td></td></tr><tr><td>मुह्</td><td>moha m. &quot;Verwirrung, Verblendung, Irrtum&quot;</td></tr><tr><td>मोह</td><td></td></tr><tr><td>krudh 4 P &quot;zürnen&quot;</td><td></td></tr><tr><td>क्रुध्</td><td>krodha m. &quot;Zorn&quot;</td></tr><tr><td>क्रोध</td><td></td></tr><tr><td>kup 4 P &quot;zürnen&quot;</td><td></td></tr><tr><td>कुप्</td><td>kopa m. &quot;Zorn&quot;</td></tr><tr><td>कोप</td><td></td></tr><tr><td>lubh 4 P &quot;begehren&quot;</td><td></td></tr><tr><td>लुभ्</td><td>lobha m. &quot;Begierde&quot;</td></tr><tr><td>लोभ</td><td></td></tr><tr><td>labh 1 Ā &quot;bekommen&quot;</td><td></td></tr><tr><td>लभ्</td><td>lābha m. &quot;das Bekommen, Gewinn&quot;</td></tr><tr><td>लाभ</td><td></td></tr><tr><td>sṛj 6 P &quot;loslassen, emanieren lassen&quot;</td><td></td></tr><tr><td>सृज्</td><td>sarga m. &quot;das Loslassen, die Emanation, die Schöpfung&quot; (zum Wortsandhi j » g siehe später)</td></tr><tr><td>सर्ग</td><td></td></tr><tr><td>śru 5 P &quot;hören&quot;</td><td></td></tr><tr><td>श्रु</td><td>śrava m. &quot;das Hören&quot;</td></tr><tr><td>श्रव</td><td></td></tr><tr><td>bhū 1 P &quot;werden, sein&quot;</td><td></td></tr><tr><td>भू</td><td>bhāva m. &quot;das Werden, das (etwas) Sein, Natur, Charakter&quot;</td></tr><tr><td>भाव</td><td></td></tr><tr><td>yudh 4 Ā &quot;kämpfen&quot;</td><td></td></tr><tr><td>युध्</td><td>yodha m. &quot;Kämpfer, Krieger, Soldat&quot;</td></tr><tr><td>योध</td><td></td></tr></tbody></table><h3 id="_8-3-2-ana-n-krt" tabindex="-1">8.3.2. -ana n. (kṛt) <a class="header-anchor" href="#_8-3-2-ana-n-krt" aria-label="Permalink to &quot;8.3.2. -ana n. (kṛt)&quot;">​</a></h3><p>Das kṛt-Suffix -ana bildet meist neutrale Substantive, die eine Handlung, einen Zustand oder das Mittel bzw. Werkzeug bezeichnen, durch welches die von der Wurzel oder einem Verbalstamm bezeichnete Handlung zustande gebracht wird. Für eine kurze Penultima oder einen auslautenden Vokal der Wurzel wird gewöhnlich Hochstufe (guṇa) substituiert.</p><p>Beispiele.</p><table tabindex="0"><thead><tr><th>Wurzel</th><th>+ -ana (kṛt)</th></tr></thead><tbody><tr><td>gam 1 P &quot;gehen&quot;</td><td></td></tr><tr><td>गम्</td><td>gamana n. &quot;das Gehen&quot;</td></tr><tr><td>गमन</td><td></td></tr><tr><td>nī 1 U &quot;führen&quot;</td><td></td></tr><tr><td>नी</td><td>nayana n. &quot;(das Werkzeug des Führens, d.h.) Auge&quot;</td></tr><tr><td>नयन</td><td></td></tr><tr><td>śru 5 P &quot;hören&quot;</td><td></td></tr><tr><td>श्रु</td><td>śravaṇa n. &quot;(Hörwerkzeug =) Ohr&quot;</td></tr><tr><td>श्रवन</td><td></td></tr><tr><td>kṛ 8 U &quot;tun&quot;</td><td></td></tr><tr><td>कृ</td><td>kāraṇa n. &quot;(das, wodurch etwas getan wird, d.h.) Ursache, Grund&quot;</td></tr><tr><td>कारण</td><td></td></tr><tr><td>bhū 1 P &quot;werden&quot;</td><td></td></tr><tr><td>भू</td><td>bhavana n. &quot;das Werden, Entstehen&quot;</td></tr><tr><td>भवन</td><td></td></tr><tr><td>dṛś 4 P &quot;sehen&quot;</td><td></td></tr><tr><td>दृश्</td><td>darśana n. &quot;das Sehen, Sichtweise, philosophisches System, Erscheinung, speziell: Darśan&quot;</td></tr><tr><td>दर्शनस्</td><td></td></tr></tbody></table><p><img src="'+n+'" alt=""><br> Abb.: Maa Batakali Darshan, Puri, Orissa<br> [Bildquelle: savia. -- <a href="http://www.flickr.com/photos/savia/383440967/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/savia/383440967/</a>. -- Zugriff am 2008-11-22. --<a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><blockquote><p>&quot;Darshan oder Darshana  ist ein Begriff aus dem Hinduismus für die Sicht und Vision des Heiligen und Göttlichen. Unter <em>Darshana</em> wird z.B. das offizielle Treffen von Schüler und Meister verstanden, bei dem der Schüler vom Meister geladen wurde. Es kann aber auch das <em>sich Versenken</em> beim Betrachten eines Götterbildes bedeuten. Letztere Bedeutung ist diejenige, die im heutigen Sprachgebrauch des Hindi die häufigste ist. Im Zusammenhang mit Mata Amritanandamayi bedeutet Darshan die Umarmung durch den Guru.</p><p>Fromme Hindus gehen in den Tempel um die Sicht Gottes durch ein Symbol oder eine Statue, in der die geistige Anwesenheit der Gottheit angenommen wird, zu erlangen. In diesem Sinne auch eine Segnung durch die Gottheit. Darshan kann jedoch auch durch eine Vision der Gottheit bei Gebet oder der Meditation empfangen werden. Auch eine lebendige Person, die als Inkarnation der Gottheit angesehen wird, wie z. Bsp. ein Avatara, kann Darshan geben.&quot;</p><p>[Quelle: <a href="http://de.wikipedia.org/wiki/Darshan" target="_blank" rel="noreferrer">http://de.wikipedia.org/wiki/Darshan</a>. -- Zugriff am 2008-11-22]</p></blockquote><h3 id="_8-3-3-tra-n-krt" tabindex="-1">8.3.3. -tra n. (kṛt) <a class="header-anchor" href="#_8-3-3-tra-n-krt" aria-label="Permalink to &quot;8.3.3. -tra n. (kṛt)&quot;">​</a></h3><p>Das kṛt-Suffix -tra bildet (meist) neutrale Substantive, welche das Mittel oder Werkzeug bezeichnen, durch welches die von der Wurzel bezeichnete Handlung zustande kommt. Kurze Penultima und auslautender Vokal der Wurzel wird durch Hochstufe (guṇa) ersetzt.</p><p>Beispiele:</p><table tabindex="0"><thead><tr><th>Wurzel</th><th>+ -tra (kṛt)</th></tr></thead><tbody><tr><td>nī 1 U &quot;führen&quot;</td><td></td></tr><tr><td>नी</td><td>netra n. &quot;(Mittel des Führens =) Auge&quot;</td></tr><tr><td>नेत्र</td><td></td></tr><tr><td>śru 5 P &quot;hören&quot;</td><td></td></tr><tr><td>श्रु</td><td>śrotra &quot;(Hörwerkzeug=) Ohr&quot;</td></tr><tr><td>श्रोत्र</td><td></td></tr><tr><td>man 4 Ā &quot;denken&quot;</td><td></td></tr><tr><td>मन्</td><td>mantra m. (!) &quot;(Denkwerkzeug:) Spruch, &#39;magische&#39; Formel (Mantra)&quot;</td></tr><tr><td>मन्त्र</td><td></td></tr><tr><td>tan 8 U &quot;aufspannen&quot;</td><td></td></tr><tr><td>तन्</td><td>tantra n. &quot;Webkette&quot;</td></tr><tr><td>तन्त्र</td><td></td></tr></tbody></table><p></p><table><caption>**Das Ur-Mantra Oṃ (ॐ) in verschiedenen indischen Schriften**</caption><tbody><tr><td><img src="'+i+'"><br>Abb.: In Devanāgarī<br>देवनागरी</td><td><img src="'+u+'"><br>Abb.: In Bengali Schrift<br>বাংলা লিপি</td></tr><tr><td><img src="'+s+'"><br>Abb.: In Kannaresischer Schrift<br>ಕನ್ನಡ</td><td><img src="'+l+'"><br>Abb.: In Tamil-Schrift<br>தமிழ் அரிச்சுவடி</td></tr><tr><td><img src="'+o+'"><br>Abb.: In Malayalam-Schrift<br>മലയാളം</td><td><img src="'+h+'"><br>Abb.: Jaina-Oṃ<br></td></tr><tr><td colspan="2">[Bildquelle für alle Oṃs: Wikipedia, Public domain]</td></tr></tbody></table><h3 id="_8-3-4-ti-f-krt" tabindex="-1">8.3.4. -ti f. (kṛt) <a class="header-anchor" href="#_8-3-4-ti-f-krt" aria-label="Permalink to &quot;8.3.4. -ti f. (kṛt)&quot;">​</a></h3><p>Das kṛt-Suffix -ti bildet feminine Substantive, die im Allgemeinen die von der Wurzel bezeichnete Handlung oder den von der Wurzel bezeichneten Zustand ausdrückt. Die Form der Wurzel ist tiefstufig.</p><p>Beispiele:</p><table tabindex="0"><thead><tr><th>Wurzel</th><th>+ -ti (kṛt)</th></tr></thead><tbody><tr><td>śru 5 P &quot;hören&quot;</td><td></td></tr><tr><td>श्रु</td><td>śruti f. &quot;das Hören, der Veda&quot;</td></tr><tr><td>श्रुति</td><td></td></tr><tr><td>smṛ 1 P &quot;vergegenwärtigen&quot;</td><td></td></tr><tr><td>स्मृ</td><td>smṛti f. &quot;Das Vergegenwärtigen, Erinnerung, Überlieferung, Achtsamkeit&quot;</td></tr><tr><td>स्मृति</td><td></td></tr><tr><td>nī 1 U &quot;führen&quot;</td><td></td></tr><tr><td>नी</td><td>nīti f. &quot;das Führen, Führung, Betragen&quot;</td></tr><tr><td>नीति</td><td></td></tr><tr><td>sṛj 6 P &quot;emanieren lassen&quot;</td><td></td></tr><tr><td>सृज्</td><td>sṛṣṭi f. &quot;Emanation, Schöpfung&quot;</td></tr><tr><td>सृष्टि</td><td></td></tr><tr><td>dṛś 4 P &quot;sehen&quot;स्</td><td></td></tr><tr><td>दृश्</td><td>dṛṣṭi f. &quot;Blick, Gesicht, Sehweise&quot; (zum Wortsandhi siehe später)</td></tr><tr><td>दृष्टि</td><td></td></tr><tr><td>gam 1 P &quot;gehen&quot;</td><td></td></tr><tr><td>गम्</td><td>gati f. &quot;Gang, Laufbahn, Ziel des Gehens&quot; (aus *gm » ga + -ti)</td></tr><tr><td>गति</td><td></td></tr><tr><td>man 4 Ā &quot;denken&quot;</td><td></td></tr><tr><td>मन्</td><td>mati f. &quot;Denken, Gedanke, Meinung&quot; (aus *mn » ma + -ti)</td></tr><tr><td>मति</td><td></td></tr></tbody></table><p>* Anmerkung: * vor einer Form bedeutet, dass diese Form im Sanskrit nicht vorkommt, sondern theoretisch erschlossen ist als Voraussetzung für eine bestimmte Bildung. Die Tiefstufe von gam ist gøm = *gm, das m wird als sogenannte nasalis sonans durch a ersetzt » ga; Analoges gilt für man » ma.</p><h3 id="_8-3-5-tva-n-ta-f-taddhita" tabindex="-1">8.3.5. -tva n., tā f. (taddhita) <a class="header-anchor" href="#_8-3-5-tva-n-ta-f-taddhita" aria-label="Permalink to &quot;8.3.5. -tva n., tā f. (taddhita)&quot;">​</a></h3><p>Die taddhita-Suffixe -tva n. bzw. -tā f. bilden abstrakte Substantive zu Nomina. Die Form des zugrundeliegenden Nominalstamms bleibt unverändert.</p><p>Beispiele:</p><table tabindex="0"><thead><tr><th>Noinalstamm</th><th>+ -tva n. (taddhita)</th><th>+ tā f. (taddhita)</th><th>Bedeutung</th></tr></thead><tbody><tr><td>guru 3 &quot;schwer, würdig, m. Meister&quot;</td><td></td><td></td><td></td></tr><tr><td>गुरु</td><td>gurutva n.</td><td></td><td></td></tr><tr><td>गुरुत्व</td><td>gurutā f.</td><td></td><td></td></tr><tr><td>गुरुता</td><td>&quot;Schwere, Ehrwürdigkeit, Das Lehrersein (Wesen oder Natur eines Lehrers)</td><td></td><td></td></tr><tr><td>brāhmaṇa m. &quot;Brahmane&quot;</td><td></td><td></td><td></td></tr><tr><td>ब्राह्मण</td><td>brāhmaṇtva n.</td><td></td><td></td></tr><tr><td>ब्राह्मणत्व</td><td>brāhmaṇatā f.</td><td></td><td></td></tr><tr><td>ब्राह्मणता</td><td>&quot;das Brahmane-sein, was einen Brahmanen zum Brahmanen macht, Wesen / Natur eines Brahmanen&quot;</td><td></td><td></td></tr><tr><td>deva m. &quot;Himmlischer, Gott&quot;</td><td></td><td></td><td></td></tr><tr><td>देव</td><td></td><td>devatā f.</td><td></td></tr><tr><td>देवता</td><td>&quot;Gottheit&quot;</td><td></td><td></td></tr></tbody></table><p>Diese beiden Bildungen können praktisch zu jedem Nomen gebildet werden. Sie sind in wissenschaftlichen Sanskritwerken sehr häufig.</p><h2 id="_8-4-die-8-prasensklasse-tanadi-तनादि-tan-usw" tabindex="-1">8.4. Die 8. Präsensklasse (tanādi = तनादि = &quot;tan usw.&quot;) <a class="header-anchor" href="#_8-4-die-8-prasensklasse-tanadi-तनादि-tan-usw" aria-label="Permalink to &quot;8.4. Die 8. Präsensklasse (tanādi = तनादि = &quot;tan usw.&quot;)&quot;">​</a></h2><p>Stammbildung:</p><ul><li>Starker Stamm: Wurzel + -o-</li><li>Schwacher Stamm: Wurzel + -u- (vor Vokal: -v-)</li></ul><p>Beispiel:</p><p>tan 5 U तन् &quot;dehnen&quot;</p><blockquote><p>3. sg. P tan-o-ti तनोति</p><p>3. pl. P tan-v-anti तन्वन्ति</p><p>3. sg. Ā tan-u-te तनुते</p><p>3. pl. Ā tan-v-ate तन्वते</p></blockquote><p>Anmerkung: Zum Streit, ob tan nicht eigentlich eine Wurzel der 5. Präsensklasse ist -- *tn » ta + no- -- vgl. Thumb-Hauschild, Handbuch des Sanskrit II, 265.</p><p>Die wichtigste Wurzel, die  zur 8. Präsensklasse zählt, ist kṛ 8 U &quot;tun, machen&quot;. Ihre Konjugation ist ziemlich unregelmäßig:</p><p>kṛ 8 U &quot;machen tun&quot;</p><blockquote><p>3.sg. P kar-o-ti करोति</p><p>3. pl. P kur-v-anti कुर्वन्ति</p><p>3. sg. Ā kur-u-te कुरुते</p><p>3. pl. Ā kur-v-ate कुर्वते</p></blockquote><h2 id="_8-5-wortliste" tabindex="-1">8.5. Wortliste <a class="header-anchor" href="#_8-5-wortliste" aria-label="Permalink to &quot;8.5. Wortliste&quot;">​</a></h2><p>Lernen Sie folgende Wörter:</p><p>ji 1 P (jayati) जि जयति : siegen, besiegen, ersiegen</p><p>labh 1 Ā (labhate) लभ् लभते : fassen, erhalten, ergreifen</p><p>tu तु : aber (steht nach dem ersten Wort des entgegengesetzten Satzes oder Satzteils)</p><p>paś 4 P (paśyati) पश् पश्यति : sehen, erblicken (wird als Präsensstamm statt der Wurzel dṛś 0 &quot;sehen, erblicken&quot; verwendet)</p><p>kṛ 8 U (karoti) कृ करोति : machen, tun</p><p>tan 8 U (tanoti) तन् तनोति : dehnen</p><p>rakṣ 1 P (rakṣati) रक्ष् रक्षति : hüten</p><p>sārathi m. सारथि : Wagenlenker, Fuhrmann</p><p>kapi m. कपि : Affe</p><p>kumārī f. कुमारी : das Mädchen, die Jungfrau</p><p>nāga m. नाग : der Nackte, der Elefant, die Schlange (Elefant und Schlange haben kein Fell, ebenso wie der &quot;nackte Affe&quot; Mensch)</p><p>gaja m. गज : Elefant</p><p>śuc 1 P (śocati) शुच् शोचति : trauern</p><p>śuka m. शुक : Papagei</p><p>pat 1 P (patati) पत् पतति: fallen, fliegen</p><p>patrikā f. पत्रिका : Brief</p><p>likh 1 P (likhati) लिख् लिखति: ritzen, schreiben (ursprünglich mit dem Stichel auf einem Palmblatt, dann aber allgemein)</p><p><img src="'+p+'" alt=""><br> Abb.: लिख् : Indischer Schreibgriffel aus Stahl zum Einritzen in Palmblätter<br> [Bildquelle: Meyers Großes Konversationslexikon 1905. Gemeinfrei]</p><p><img src="'+m+'" alt=""><br> Abb.: लिख् : Schreibstöckchen der Batak (Sumatra), wie es vermutlich auch in Indien gebräuchlich war<br> [Bildquelle: Meyers Großes Konversationslexikon 1905. Gemeinfrei]</p><p>sukha n. सुख : Glück, Wohlsein</p><p>duḥkha n. दुःख : Unglück, Leid</p><h2 id="_8-6-ubung" tabindex="-1">8.6. Übung <a class="header-anchor" href="#_8-6-ubung" aria-label="Permalink to &quot;8.6. Übung&quot;">​</a></h2><p>A) Erklären Sie die folgenden Nomina durch Angabe der Wurzel, von der abgeleitet wurde, und des Nominalsuffixes. Geben Sie Geschlecht und Bedeutung an:</p><p>1. lobha</p><p>2. rakṣa</p><p>3. śrotra</p><p>4. mati</p><p>5. savana</p><p>6. yodha</p><p>7. lābha</p><p>8. kāraṇa</p><p>9. gati</p><p>10. khādana</p><p>11. smara</p><p>12. sṛṣṭi</p><p>13. tantra</p><p>14. bhāva</p><p>15. darśana</p><p>16. netra</p><p>17. veśana</p><p>18. kopa</p><p>19. sarga</p><p>20. yajana</p><p>21. moha</p><p>22. śrava</p><p>23. bhavana</p><p>24. nīti</p><p>25. nartana</p><p>26. jaya</p><p>27. nayana</p><p>28. śravaṇa</p><p>B) Bilden Sie Abstrakta zu allen bisher gelernten Nomina und überlegen Sie deren Bedeutung (mündlich)</p><p>C) Setzen Sie als direktes Objekt im Singular und Plural ein:</p><p>kṣatriyas ... rakṣati (brāhmaṇa, vaiśya, śūdra, brāhmaṇī, kṣatriyā)</p><p>D) Übersetzen Sie</p><p>1. Kṣatriyas behüten sowohl Brahmanen als auch Vaiśyas und Śūdras. (2 Möglichkeiten)</p><p>2. Ein heiliger Mann sieht sowohl Himmel als auch Höllen.</p><p>3. Er besiegt Kṣatriyas.</p><p>4. Sie spannt die Webkette auf.</p><p>5. Soldaten kämpfen.</p><p>6. Der Brahmane macht ein Feuer.</p><p>7. Brahmanen machen Feuer.</p><p>8. Was tun diese Kämpfer?</p><p>9. Wen sieht das Auge?</p><p>10. Was begehren Götter?</p><p>11. Was ist der Grund?</p><h2 id="_8-7-lese-und-ubersetzungsubung" tabindex="-1">8.7. Lese- und Übersetzungsübung <a class="header-anchor" href="#_8-7-lese-und-ubersetzungsubung" aria-label="Permalink to &quot;8.7. Lese- und Übersetzungsübung&quot;">​</a></h2><p>1. शूद्रो बालं नयति |</p><p>2. कविर्देवं यजते |</p><p>3. साधुः फलानि खादति |</p><p>4. गुरुः क्रोधं जयति |</p><p>5. देवो नरकं सृजति |</p><p>6. धेनुर्ग्रामं विशति |</p><p>7. कामक्रोधलोभा नरकं नयन्ति |</p><p>8. देवतां यजति |</p><p>9. बाला भवति |</p><p>10. सारथी रथं नयति |</p><p>11. कपयः फलानि खादन्ति |</p><p>12. बाला लिखति |</p><p>13. कुमारी गृहं विशति |</p><p>14. देवो नागं सृजति |</p><p>15. बालो गजं नयति |</p><p>16. विमला शोचति | (विमला  Eigenname Vimalā)</p><p>17. शुकः पतति |</p><p>18. बालः पत्रिकां लिखति |</p>',138)])])}const S=e(b,[["render",g]]);export{w as __pageData,S as default};
